// Route parameters (required for identification)
app.get('/api/products/:id', (req, res) => {
  const productId = req.params.id;  // 'id' from URL
  // Get product from database
  res.json({ id: productId, name: 'Widget' });
});

// Query parameters (optional filters/pagination)
app.get('/api/products', (req, res) => {
  const { category, minPrice, maxPrice, page = 1, limit = 10 } = req.query;

  // Build query based on parameters
  let query = {};
  if (category) query.category = category;
  if (minPrice || maxPrice) {
    query.price = {};
    if (minPrice) query.price.$gte = parseFloat(minPrice);
    if (maxPrice) query.price.$lte = parseFloat(maxPrice);
  }

  // Pagination
  const skip = (page - 1) * limit;

  res.json({ query, page: parseInt(page), limit: parseInt(limit) });
});

// Request body (for creating/updating resources)
app.post('/api/products', (req, res) => {
  const { name, price, category, description } = req.body;

  // Validate required fields
  if (!name || !price) {
    return res.status(400).json({ error: 'Name and price are required' });
  }

  const product = {
    id: Date.now(),
    name,
    price: parseFloat(price),
    category: category || 'general',
    description: description || ''
  };

  res.status(201).json(product);
});

// Common status codes in REST APIs
app.get('/api/users/:id', async (req, res) => {
  try {
    const user = await User.findById(req.params.id);

    if (!user) {
      return res.status(404).json({
        error: 'User not found',
        message: `No user exists with ID ${req.params.id}`
      });
    }

    res.json(user);
  } catch (error) {
    res.status(500).json({
      error: 'Internal server error',
      message: error.message
    });
  }
});

// Status code reference
const STATUS_CODES = {
  200: 'OK - Request successful',
  201: 'Created - Resource created successfully',
  204: 'No Content - Successful delete',
  400: 'Bad Request - Invalid request data',
  401: 'Unauthorized - Authentication required',
  403: 'Forbidden - Insufficient permissions',
  404: 'Not Found - Resource doesn\'t exist',
  409: 'Conflict - Resource already exists',
  422: 'Unprocessable Entity - Validation failed',
  500: 'Internal Server Error - Server problem'
};

// API Versioning
// Option 1: URL path versioning
app.use('/api/v1', v1Router);
app.use('/api/v2', v2Router);

// Option 2: Header versioning
app.use('/api', (req, res, next) => {
  const version = req.headers['accept-version'] || 'v1';
  req.apiVersion = version;
  next();
});

// Pagination implementation
app.get('/api/products', async (req, res) => {
  const page = parseInt(req.query.page) || 1;
  const limit = parseInt(req.query.limit) || 10;
  const sortBy = req.query.sortBy || 'createdAt';
  const order = req.query.order === 'desc' ? -1 : 1;

  try {
    const total = await Product.countDocuments();
    const products = await Product.find()
      .sort({ [sortBy]: order })
      .skip((page - 1) * limit)
      .limit(limit);

    res.json({
      data: products,
      pagination: {
        total,
        page,
        limit,
        totalPages: Math.ceil(total / limit),
        hasNextPage: page * limit < total,
        hasPrevPage: page > 1
      }
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// HATEOAS example
app.get('/api/users/:id', async (req, res) => {
  const user = await User.findById(req.params.id);

  const response = {
    id: user.id,
    name: user.name,
    email: user.email,
    links: {
      self: `/api/users/${user.id}`,
      posts: `/api/users/${user.id}/posts`,
      followers: `/api/users/${user.id}/followers`,
      update: `/api/users/${user.id}`,
      delete: `/api/users/${user.id}`
    }
  };

  res.json(response);
});

// Collection with links
app.get('/api/users', async (req, res) => {
  const users = await User.find();
  const page = parseInt(req.query.page) || 1;
  const limit = parseInt(req.query.limit) || 10;
  const total = await User.countDocuments();

  res.json({
    data: users,
    links: {
      self: `/api/users?page=${page}&limit=${limit}`,
      next: page * limit < total ? `/api/users?page=${page + 1}&limit=${limit}` : null,
      prev: page > 1 ? `/api/users?page=${page - 1}&limit=${limit}` : null
    }
  });
});
